  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem requires solving a self-consistent mean-field equation for occupancy in a lattice gas model. I will delegate the derivation of the transcendental equation and the numerical root-finding.",
  "helpers": [
    {
      "label": "equation_deriver",
      "instructions": "Derive the self-consistent equation for the occupancy n in a mean-field lattice gas model. Use the given parameters: energy per bond e = -(k_B T)/(2*pi), chemical potential mu = 0.1 * k_B T, and coordination numbers z_h = 4 and z_v = 8. The total coordination number z is the sum of z_h and z_v. The equation should relate n to the Boltzmann factor involving mu and the mean-field interaction energy z * e * n."
    },
    {
      "label": "numerical_solver",
      "instructions": "Solve the transcendental equation n = exp((mu - z * e * n) / (k_B T)) / (1 + exp((mu - z * e * n) / (k_B T))) for n. Use the following values: z = 12 (from 4 + 8), mu / (k_B T) = 0.1, and e / (k_B T) = -1 / (2 * pi). Provide the numerical value of n rounded to four decimal places."
    }
  ],
  "synthesis_brief": "Combine the derived mean-field equation with the numerical solution for n to provide the final occupancy value."
}

